import React, { useMemo, useState } from 'react';
import { useApp } from '../context/AppContext';
import { Search, X, Plus, Pencil } from 'lucide-react';
import { CATEGORIES } from '../data/mockData';

const FALLBACK_IMAGE = "data:image/svg+xml;charset=UTF-8,%3Csvg xmlns='http://www.w3.org/2000/svg' width='600' height='420' viewBox='0 0 600 420'%3E%3Crect width='600' height='420' fill='%23f8efe8'/%3E%3Ctext x='300' y='205' text-anchor='middle' fill='%238a7f77' font-family='Arial, sans-serif' font-size='26'%3ESin imagen%3C/text%3E%3C/svg%3E";

const initialForm = {
  name: '',
  category: '',
  price: '',
  stock: '',
  minStock: '',
  description: '',
  image: '',
};

const getImageSrc = (image) => {
  if (!image) return FALLBACK_IMAGE;
  if (image.startsWith('http') || image.startsWith('data:')) return image;
  return encodeURI(image);
};

export default function CatalogPage() {
  const { products, currentUser, addToCart, updateProduct } = useApp();
  const [search, setSearch] = useState('');
  const [category, setCategory] = useState('Todos');
  const [selected, setSelected] = useState(null);
  const [editingProduct, setEditingProduct] = useState(null);
  const [form, setForm] = useState(initialForm);

  const isStaff = currentUser?.role === 'admin' || currentUser?.role === 'vendor';

  const categories = useMemo(() => ['Todos', ...CATEGORIES.filter((item) => products.some((product) => product.category === item))], [products]);

  const filtered = useMemo(() => products.filter((product) => {
    const matchSearch = product.name.toLowerCase().includes(search.toLowerCase()) || product.description?.toLowerCase().includes(search.toLowerCase());
    const matchCategory = category === 'Todos' || product.category === category;
    return matchSearch && matchCategory;
  }), [products, search, category]);

  const openDetail = (product) => {
    setSelected(product);
    if (isStaff) {
      setEditingProduct(product);
      setForm({
        name: product.name || '',
        category: product.category || '',
        price: product.price ?? '',
        stock: product.stock ?? '',
        minStock: product.minStock ?? '',
        description: product.description || '',
        image: product.image || '',
      });
    }
  };

  const closeDetail = () => {
    setSelected(null);
    setEditingProduct(null);
    setForm(initialForm);
  };

  const saveProduct = (event) => {
    event.preventDefault();
    if (!editingProduct) return;

    updateProduct(editingProduct.id, {
      name: form.name,
      category: form.category,
      price: parseFloat(form.price),
      stock: parseInt(form.stock, 10),
      minStock: parseInt(form.minStock, 10),
      description: form.description,
      image: form.image,
    });

    closeDetail();
  };

  return (
    <div>
      <div style={{ marginBottom: 28 }}>
        <h1 style={{ fontSize: '2rem', color: 'var(--gray-700)', marginBottom: 4 }}>Catálogo</h1>
        <p style={{ color: 'var(--gray-400)' }}>Descubre nuestros dulces tradicionales de la ciudad de Cuenca</p>
      </div>

      <div style={{ display: 'flex', gap: 12, marginBottom: 22, flexWrap: 'wrap' }}>
        <div style={{ position: 'relative', flex: 1, minWidth: 220 }}>
          <Search size={15} style={{ position: 'absolute', left: 12, top: '50%', transform: 'translateY(-50%)', color: 'var(--gray-300)' }} />
          <input
            value={search}
            onChange={(event) => setSearch(event.target.value)}
            placeholder="Buscar dulces..."
            style={{ paddingLeft: 36, padding: '10px 14px 10px 36px', border: '1.5px solid var(--gray-200)', borderRadius: 'var(--radius-md)', width: '100%', fontSize: '0.9rem', outline: 'none', background: 'white' }}
          />
        </div>
        <div style={{ display: 'flex', gap: 6, flexWrap: 'wrap' }}>
          {categories.map((item) => (
            <button
              key={item}
              type="button"
              onClick={() => setCategory(item)}
              className={`btn btn-sm ${category === item ? 'btn-primary' : 'btn-secondary'}`}
            >
              {item}
            </button>
          ))}
        </div>
      </div>

      {filtered.length === 0 ? (
        <div className="empty-state" style={{ padding: '80px 20px' }}>
          <span style={{ fontSize: '3rem' }}>🔍</span>
          <p>No encontramos productos con ese criterio</p>
        </div>
      ) : (
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(220px, 1fr))', gap: 18 }}>
          {filtered.map((product) => (
            <div key={product.id} className="card" style={{ overflow: 'hidden' }}>
              <button
                type="button"
                onClick={() => openDetail(product)}
                style={{ width: '100%', border: 'none', background: 'transparent', padding: 0, textAlign: 'left' }}
              >
                <div style={{ background: 'linear-gradient(135deg, var(--pink-100), var(--brown-100))', padding: '14px', height: 220, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                  <img
                    src={getImageSrc(product.image)}
                    alt={product.name}
                    onError={(event) => { event.currentTarget.src = FALLBACK_IMAGE; }}
                    style={{ width: '100%', height: '100%', objectFit: 'cover', borderRadius: '18px', display: 'block' }}
                  />
                </div>
                <div style={{ padding: '16px' }}>
                  <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: 4, gap: 8 }}>
                    <h3 style={{ fontSize: '0.95rem', fontFamily: 'var(--font-display)' }}>{product.name}</h3>
                    <span style={{ fontWeight: 700, color: 'var(--pink-500)', whiteSpace: 'nowrap' }}>${product.price.toFixed(2)}</span>
                  </div>
                  <p style={{ fontSize: '0.78rem', color: 'var(--gray-400)', marginBottom: 10 }}>{product.category}</p>
                  <p style={{ fontSize: '0.82rem', color: 'var(--gray-500)', marginBottom: 10 }}>Stock: {product.stock} · {product.available ? 'Disponible' : 'Agotado'}</p>
                  <span className={`badge ${product.stock === 0 ? 'badge-danger' : product.stock <= product.minStock ? 'badge-warning' : 'badge-success'}`} style={{ width: '100%', justifyContent: 'center', display: 'flex' }}>
                    {product.stock === 0 ? 'Agotado' : product.stock <= product.minStock ? 'Stock bajo' : 'Disponible'}
                  </span>
                </div>
              </button>

              <div style={{ display: 'flex', gap: 8, padding: '0 16px 16px', flexWrap: 'wrap' }}>
                {isStaff ? (
                  <button type="button" className="btn btn-secondary btn-sm" style={{ width: '100%', justifyContent: 'center' }} onClick={() => openDetail(product)}>
                    <Pencil size={14} /> Editar producto
                  </button>
                ) : (
                  <button
                    type="button"
                    className="btn btn-primary btn-sm"
                    style={{ width: '100%', justifyContent: 'center' }}
                    disabled={!product.available}
                    onClick={() => addToCart(product, 1)}
                  >
                    <Plus size={14} /> {product.available ? 'Agregar al carrito' : 'Agotado'}
                  </button>
                )}
              </div>
            </div>
          ))}
        </div>
      )}

      {selected && (
        <div className="modal-overlay" onClick={closeDetail}>
          <div className="modal" style={{ maxWidth: 620 }} onClick={(event) => event.stopPropagation()}>
            <div className="modal-header">
              <div>
                <h2>{isStaff ? 'Editar producto' : selected.name}</h2>
                <p className="section-subtitle">{selected.category}</p>
              </div>
              <button type="button" className="btn btn-secondary" onClick={closeDetail}><X size={18} /> Cerrar</button>
            </div>

            {isStaff ? (
              <form onSubmit={saveProduct} className="vendor-dashboard__product-form">
                <div className="form-group">
                  <label>Nombre</label>
                  <input value={form.name} onChange={(event) => setForm({ ...form, name: event.target.value })} />
                </div>
                <div className="form-group">
                  <label>Categoría</label>
                  <select value={form.category} onChange={(event) => setForm({ ...form, category: event.target.value })}>
                    {CATEGORIES.map((item) => <option key={item} value={item}>{item}</option>)}
                  </select>
                </div>
                <div className="form-group">
                  <label>Precio</label>
                  <input type="number" step="0.01" value={form.price} onChange={(event) => setForm({ ...form, price: event.target.value })} />
                </div>
                <div className="form-group">
                  <label>Stock</label>
                  <input type="number" value={form.stock} onChange={(event) => setForm({ ...form, stock: event.target.value })} />
                </div>
                <div className="form-group">
                  <label>Stock mínimo</label>
                  <input type="number" value={form.minStock} onChange={(event) => setForm({ ...form, minStock: event.target.value })} />
                </div>
                <div className="form-group form-group--wide">
                  <label>Imagen</label>
                  <input value={form.image} onChange={(event) => setForm({ ...form, image: event.target.value })} placeholder="/img/dulces/... o URL" />
                </div>
                <div className="form-group form-group--wide">
                  <label>Descripción</label>
                  <textarea value={form.description} onChange={(event) => setForm({ ...form, description: event.target.value })} rows={3} />
                </div>
                <div className="form-actions">
                  <button type="submit" className="btn btn-primary">Guardar cambios</button>
                </div>
              </form>
            ) : (
              <>
                <div style={{ marginBottom: 18 }}>
                  <img src={getImageSrc(selected.image)} alt={selected.name} onError={(event) => { event.currentTarget.src = FALLBACK_IMAGE; }} style={{ width: '100%', height: 280, objectFit: 'cover', borderRadius: '18px' }} />
                </div>
                <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3, minmax(0, 1fr))', gap: 12 }}>
                  <div className="card" style={{ padding: 12 }}><p className="text-muted">Precio</p><strong>${selected.price.toFixed(2)}</strong></div>
                  <div className="card" style={{ padding: 12 }}><p className="text-muted">Stock</p><strong>{selected.stock}</strong></div>
                  <div className="card" style={{ padding: 12 }}><p className="text-muted">Categoría</p><strong>{selected.category}</strong></div>
                </div>
                <p style={{ color: 'var(--gray-500)', marginTop: 18 }}>{selected.description}</p>
                <div className="modal-footer">
                  <button type="button" className="btn btn-secondary" onClick={closeDetail}>Cerrar</button>
                  <button type="button" className="btn btn-primary" disabled={!selected.available} onClick={() => addToCart(selected, 1)}>
                    <Plus size={14} /> {selected.available ? 'Agregar al carrito' : 'Agotado'}
                  </button>
                </div>
              </>
            )}
          </div>
        </div>
      )}
    </div>
  );
}
